import{_ as t,C as i,o as s,c as r,ag as a,E as l,w as n,a as d}from"./chunks/framework.BZohXCq9.js";const q=JSON.parse('{"title":"¿Qué es SYNTIfood?","description":"Menú digital para restaurantes con pedidos por WhatsApp","frontmatter":{"title":"¿Qué es SYNTIfood?","description":"Menú digital para restaurantes con pedidos por WhatsApp"},"headers":[],"relativePath":"food/que-es-food.md","filePath":"food/que-es-food.md"}'),p={name:"food/que-es-food.md"};function c(u,e,m,f,h,_){const o=i("Note");return s(),r("div",null,[e[1]||(e[1]=a('<p>SYNTIfood es el producto de SYNTIweb diseñado especialmente para <strong>restaurantes, fondas, comidas rápidas y cualquier negocio de comida</strong>.</p><p>Tu cliente escanea el QR en tu mesa o recibe el link por WhatsApp, ve tu menú completo con fotos y precios, y te hace el pedido directamente por WhatsApp — sin apps, sin cuentas, sin complicaciones.</p><h2 id="el-problema-que-resuelve" tabindex="-1">El problema que resuelve <a class="header-anchor" href="#el-problema-que-resuelve" aria-label="Permalink to &quot;El problema que resuelve&quot;">​</a></h2><p>La carta en papel se ensucia, se desactualiza y hay que reimprimir cada vez que cambia el precio. Con SYNTIfood actualizas el menú desde el celular en segundos y todos los clientes ven el precio correcto de inmediato.</p><h2 id="como-funciona-el-menu" tabindex="-1">Cómo funciona el menú <a class="header-anchor" href="#como-funciona-el-menu" aria-label="Permalink to &quot;Cómo funciona el menú&quot;">​</a></h2><p>El menú de SYNTIfood tiene una estructura simple y efectiva:</p><ul><li><strong>Categorías</strong> con foto representativa (Entradas, Carnes, Bebidas, etc.)</li><li><strong>Lista de platos</strong> dentro de cada categoría con nombre y precio</li><li><strong>Precio en REF y bolívares</strong> actualizado con la tasa BCV del día</li></ul><h2 id="para-que-tipo-de-negocio-es-ideal" tabindex="-1">Para qué tipo de negocio es ideal <a class="header-anchor" href="#para-que-tipo-de-negocio-es-ideal" aria-label="Permalink to &quot;Para qué tipo de negocio es ideal&quot;">​</a></h2><ul><li>Restaurantes y fondas</li><li>Comidas rápidas y hamburguesas</li><li>Pizzerías</li><li>Reposterías y panaderías</li><li>Heladerías</li><li>Cualquier negocio donde el cliente elige de una lista de platos</li></ul>',9)),l(o,null,{default:n(()=>[...e[0]||(e[0]=[d(" Si además de comida vendes productos físicos con tallas o colores, SYNTIcat puede ser más adecuado. Si tienes dudas, escríbenos por WhatsApp. ",-1)])]),_:1}),e[2]||(e[2]=a('<h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/food/que-es-syntifood.html">¿Qué es SYNTIfood? (detallado)</a> — Comparativa, planes y ejemplo completo</li><li><a href="/food/categorias-menu.html">Categorías del menú</a> — Cómo organizar tu carta</li><li><a href="/food/pedido-rapido-whatsapp.html">Pedido Rápido</a> — Cómo tus clientes piden por WhatsApp</li></ul>',2))])}const b=t(p,[["render",c]]);export{q as __pageData,b as default};
